insert into offmarket.business_scores (business_id, score_run_id, layer1_base_rate, layer1_comment, layer2_sellability, layer2_comment, layer3_behavioral_trigger, layer3_comment, layer4_market_pull, layer4_comment, final_score, final_tier, final_comment, value_add_thesis, confidence, data_completeness) values
('59011348-022b-54e9-a8c7-1746f14584f5', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 50, '40+ year practice (Energy Corridor/Memorial), but the current owner Dr. Motii succeeded the founder (Dr. Battarbee) more recently — likely ~15-20 yrs ownership, age proxy ~50-58. Not yet at a natural-exit window; the long history is the practice''s, not the owner''s. Low-medium confidence.', 72, 'Established Memorial/Energy Corridor general/cosmetic/family practice with a long-tenured staff (hygienist since 1993) and recurring hygiene base; solo GP in an affluent ZIP; SBA-financeable. Smaller review footprint trims it.', 46, 'Mixed: dated-feeling web brand and a single provider lean coasting, but the owner is mid-career and there''s no strong stack of decay/decline tells. Moderate-low L3.', 82, 'Energy Corridor / Memorial Houston (77079) is a desirable, stable catchment with DSO interest.', 59, 'C_watch', 'Dr. Mogdeh Motii, ~55 (license_tenure_proxy), runs Generations Family Dentistry (Mogdeh Motii, DDS) in Houston, Harris County. 40+ year practice (Energy Corridor/Memorial), but the current owner Dr. Motii succeeded the founder (Dr. Battarbee) more recently — likely ~15-20 yrs ownership, age proxy ~50-58. Not yet at a natural-exit window; the long history is the practice''s, not the owner''s. Low-medium confidence. Mixed: dated-feeling web brand and a single provider lean coasting, but the owner is mid-career and there''s no strong stack of decay/decline tells. Moderate-low L3. Energy Corridor / Memorial Houston (77079) is a desirable, stable catchment with DSO interest. Composite 59/100. Tier C — re-score in ~90 days.', 'Online scheduling + AI front desk + recall automation + website refresh; modern PMS — incremental EBITDA over 2 years; better as a ''forward'' than a Gideon-acquires play given owner age.', 'low', 0.4),
('ff968222-bd06-56a9-8a08-7df15cea9e33', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 22, 'Practice established 2012, owner Dr. Vlachakis is clearly mid-career (UTHSC Houston grad) — tenure proxy ~42-48, nowhere near a natural-exit window. Low L1.', 66, 'Clean, well-reviewed Memorial-area general/pediatric practice, recurring hygiene base, but only ~14 yrs old and small — meets the 5-yr gate, but a younger, smaller solo practice is a modest acquisition target.', 24, 'No real coasting tells — active web presence, mid-career owner, recent reviews. Low L3.', 80, 'Memorial Houston 77024 is a premium catchment with DSO interest, but a young small solo practice draws less buy-side intensity than an established one.', 42, 'D_pass', 'Dr. Amy Vlachakis, ~45 (license_tenure_proxy), runs Healthy Smiles Family Dentistry (Amy Vlachakis, DDS) in Houston, Harris County. Practice established 2012, owner Dr. Vlachakis is clearly mid-career (UTHSC Houston grad) — tenure proxy ~42-48, nowhere near a natural-exit window. Low L1. No real coasting tells — active web presence, mid-career owner, recent reviews. Low L3. Memorial Houston 77024 is a premium catchment with DSO interest, but a young small solo practice draws less buy-side intensity than an established one. Composite 42/100. Tier D — pass for now.', 'N/A near-term — owner not winding down. Watch list at best.', 'low', 0.4),
('96133552-76b7-59f4-a08f-30ebf7c33345', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 15, 'Practice established 2019; young owners. Far from any natural-exit window. Low L1.', 58, 'Healthy, well-reviewed (4.6, 167 reviews) Champions/Willowbrook general+ortho practice, 2 providers — but only ~7 yrs old. Caps near the 5-yr gate; modest target.', 20, 'No coasting tells — new practice, active marketing, fresh reviews. Low L3.', 78, 'NW Houston (Champions/Willowbrook) is a decent DSO catchment, but a young small practice is a low-intensity target.', 37, 'D_pass', 'Drs. Sneha Hanchate & Husain Kapadia, ~40 (license_tenure_proxy), runs Vintage Smile Family Dentistry (Sneha Hanchate, DDS & Husain Kapadia, DDS) in Houston, Harris County. Practice established 2019; young owners. Far from any natural-exit window. Low L1. No coasting tells — new practice, active marketing, fresh reviews. Low L3. NW Houston (Champions/Willowbrook) is a decent DSO catchment, but a young small practice is a low-intensity target. Composite 37/100. Tier D — pass for now.', 'N/A near-term. Track for the future.', 'low', 0.4),
('00abceae-09a7-5561-a2ec-a0c756aa8bad', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 68, 'Practice has operated since 1991 (~35 yrs); tenure proxy ~56-62 — solid natural-exit profile. Brazoria County (Pearland), not a top-3 county, so deprioritized but credible. Low-medium confidence.', 74, 'Long-established Pearland/Friendswood general/family practice, recurring hygiene base, ~6 staff, clean record; SBA-financeable. Suburban Brazoria caps demand vs. core metros.', 55, 'Some coasting tells consistent with a 35-yr solo practice; specific decay/decline data not fully verified — moderate L3, lower confidence.', 78, 'Pearland/Friendswood is a high-growth south-Houston suburb with real DSO interest; outside the core 3 counties so a half-step down.', 67, 'B_forward', 'Dr. Anh B. Dao, ~58 (license_tenure_proxy), runs Anh B. Dao, DDS (Melody Lane Dental Group / Pearwood Smiles) in Pearland, Brazoria County. Practice has operated since 1991 (~35 yrs); tenure proxy ~56-62 — solid natural-exit profile. Brazoria County (Pearland), not a top-3 county, so deprioritized but credible. Low-medium confidence. Some coasting tells consistent with a 35-yr solo practice; specific decay/decline data not fully verified — moderate L3, lower confidence. Pearland/Friendswood is a high-growth south-Houston suburb with real DSO interest; outside the core 3 counties so a half-step down. Composite 67/100. Tier B — hand to the buyer / searcher community.', 'AI front desk + recall automation + online scheduling + modern PMS to capture Pearland''s growth; associate-to-equity path — solid 2-year EBITDA upside.', 'low', 0.4),
('d9330a62-42d0-5557-8c31-19c1371f7575', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 45, 'Practice operating since 1987 (~39 yrs), but ownership/principal-dentist identity and age not verified; multi-location structure suggests possibly a group or DSO-style operator rather than a single coasting owner. Treat L1 as moderate-uncertain. Low confidence.', 78, 'Long-established 4-location Fort Bend group (since 1987) — clearly a real, financeable, recurring-revenue business of meaningful size; the unknown is owner structure.', 38, 'Multi-location group expansion is the opposite of a coasting solo owner; without owner-level decay signals this is a low-moderate L3 and lower-confidence call.', 80, 'Fort Bend County (Sugar Land etc.) is a strong, affluent, high-growth catchment with active DSO/PE interest.', 56, 'C_watch', 'Owner, age unknown, runs Fort Bend Dental in Sugar Land, Fort Bend County. Practice operating since 1987 (~39 yrs), but ownership/principal-dentist identity and age not verified; multi-location structure suggests possibly a group or DSO-style operator rather than a single coasting owner. Treat L1 as moderate-uncertain. Low confidence. Multi-location group expansion is the opposite of a coasting solo owner; without owner-level decay signals this is a low-moderate L3 and lower-confidence call. Fort Bend County (Sugar Land etc.) is a strong, affluent, high-growth catchment with active DSO/PE interest. Composite 56/100. Tier C — re-score in ~90 days.', 'If single-owner: standard recall/AI/scheduling stack across all 4 locations. If group/DSO-owned: not a target. Needs an ownership check before acting.', 'low', 0.3),
('d91e776e-027b-5c86-992c-78fa5f8cf6e3', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 25, 'The practice itself is ~30 yrs old, but Dr. Doyle only bought it in 2019 (~7 yrs as owner) and is clearly early/mid-career — far from a natural-exit window. Note Dr. Ronald K. Rich (MAGD) appears to be a senior associate, possibly the prior owner winding down. Low L1 for Doyle as principal.', 78, 'Established multi-provider Sugar Land general/family practice, recurring hygiene base, ~10 staff, clean record — genuinely sellable and bankable; the owner just isn''t a seller.', 30, 'Newly-energized practice under a recent buyer — not coasting. Low L3.', 82, 'Sugar Land 77479 (Fort Bend) is a top-tier affluent suburb with strong acquirer demand.', 48, 'C_watch', 'Dr. James L. Doyle, ~42 (license_tenure_proxy), runs James L. Doyle, DDS (with Kali J. Willis, DDS & Ronald K. Rich, DDS) in Sugar Land, Fort Bend County. The practice itself is ~30 yrs old, but Dr. Doyle only bought it in 2019 (~7 yrs as owner) and is clearly early/mid-career — far from a natural-exit window. Note Dr. Ronald K. Rich (MAGD) appears to be a senior associate, possibly the prior owner winding down. Low L1 for Doyle as principal. Newly-energized practice under a recent buyer — not coasting. Low L3. Sugar Land 77479 (Fort Bend) is a top-tier affluent suburb with strong acquirer demand. Composite 48/100. Tier C — re-score in ~90 days.', 'N/A near-term — recent buyer. Watch.', 'low', 0.4),
('2d4c38bb-641a-5df5-b0c1-a9d8e66c8872', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 58, 'Dr. Welty earned her DDS in 1995 (~31 yrs licensed) and opened the Spring office in 2004 (~22 yrs as owner); tenure proxy ~52-58 — approaching but not yet in the prime exit window. Medium-low confidence.', 74, 'Established Spring (NW Harris) general+cosmetic+perio-procedures family practice, recurring hygiene base, ~6 staff, clean record; SBA-financeable. Solo GP in a solid suburb.', 50, 'A 22-yr solo practice with a single provider has coasting potential, but the web presence is reasonably maintained and there''s no strong decline stack verified — moderate L3.', 82, 'Spring/Klein (NW Harris County) is a populous, growing suburb with active DSO/PE interest.', 63, 'B_forward', 'Dr. Melissa L. Welty, ~56 (license_tenure_proxy), runs Klein Crossing Dental (Melissa L. Welty, DDS) in Spring, Harris County. Dr. Welty earned her DDS in 1995 (~31 yrs licensed) and opened the Spring office in 2004 (~22 yrs as owner); tenure proxy ~52-58 — approaching but not yet in the prime exit window. Medium-low confidence. A 22-yr solo practice with a single provider has coasting potential, but the web presence is reasonably maintained and there''s no strong decline stack verified — moderate L3. Spring/Klein (NW Harris County) is a populous, growing suburb with active DSO/PE interest. Composite 63/100. Tier B — hand to the buyer / searcher community.', 'AI front desk + recall automation + online scheduling + modern PMS; associate-to-equity path — 2-year EBITDA upside in a growth suburb. Re-score in ~12-18 months as the owner ages further.', 'low', 0.45),
('3d0f402f-71ca-506e-96ce-a4784948c9b8', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 88, 'Dr. Leffall has ~42 years of dental experience (grad ~1983/84), founded the practice with her late husband Dr. Lindell Leffall Jr. in 1985, and is now the sole owner/CEO — tenure proxy ~67-70, squarely in the natural-exit window, with no junior partner. The co-founder''s death and her age make a sale highly plausible in 1-3 yrs. Medium confidence (proxy age, but consistent across sources). NPI 1144399460.', 72, 'Clean 41-year recurring-revenue general/family practice serving the Oak Cliff/Duncanville/Cedar Hill/DeSoto corridor, ~6 staff, established book; solo GP — caps slightly; plausible SBA 7(a) size. Practice continuity questions (sole aging owner) are why a buyer wants it, not a knock on quality.', 72, 'Strong coasting profile: sole listed provider with no associate, founder near a natural exit after the co-founder''s death, dated web brand, no visible recent expansion or hiring, single location of 40+ yrs. Healthy P&L, disengaged operating posture — not distress.', 84, 'Dallas is a top-tier DSO/PE dental market; an established Oak Cliff practice with a loyal multigenerational base is a clean SBA-financeable bolt-on, and the buyer community actively seeks transition-ready solo practices.', 79, 'A_acquire_self', 'Dr. Martia Lewis Leffall, ~68 (license_tenure_proxy), runs Leffall Family Dentistry, P.C. (Martia Lewis Leffall, DDS) in Dallas, Dallas County. Dr. Leffall has ~42 years of dental experience (grad ~1983/84), founded the practice with her late husband Dr. Lindell Leffall Jr. in 1985, and is now the sole owner/CEO — tenure proxy ~67-70, squarely in the natural-exit window, with no junior partner. The co-founder''s death and her age make a sale highly plausible in 1-3 yrs. Medium confidence (proxy age, but consistent across sources). NPI 1144399460. Strong coasting profile: sole listed provider with no associate, founder near a natural exit after the co-founder''s death, dated web brand, no visible recent expansion or hiring, single location of 40+ yrs. Healthy P&L, disengaged operating posture — not distress. Dallas is a top-tier DSO/PE dental market; an established Oak Cliff practice with a loyal multigenerational base is a clean SBA-financeable bolt-on, and the buyer community actively seeks transition-ready solo practices. Composite 79/100. Tier A — Gideon should pursue this one directly.', 'AI front desk + automated recall to reactivate the lapsed-hygiene base, online scheduling, modern PMS migration, automated review generation, and an associate-to-owner glide path — a credible 1.5-2x EBITDA path over 18-24 months in a stable urban catchment.', 'medium', 0.6)
